def classify(text):
    text = text.lower()
    scores = {"business": 0, "tech": 0, "sports": 0, "world": 0}
    words = text.split()
    for w in words:
        w = w.strip(".,?!")
        if w in business_keywords: scores["business"] += 1
        if w in tech_keywords: scores["tech"] += 1
        if w in sports_keywords: scores["sports"] += 1
        if w in world_keywords: scores["world"] += 1

    if all(v == 0 for v in scores.values()): return "unknown"
    return max(scores, key=scores.get)

